param([Parameter(Mandatory=$true)][string]$ForecastPath,[Parameter(Mandatory=$true)][int]$HomeGoals,[Parameter(Mandatory=$true)][int]$AwayGoals,[string]$ProjectRoot='')
$ErrorActionPreference='Stop';if(!$ProjectRoot){$ProjectRoot=Split-Path -Parent (Split-Path -Parent $MyInvocation.MyCommand.Path)};Import-Module (Join-Path $ProjectRoot 'src\HandicapModel.psm1') -Force;$f=Get-Content -Raw -Encoding UTF8 $ForecastPath|ConvertFrom-Json;$a=Get-HandicapPostMatchAudit $f $HomeGoals $AwayGoals;$a|Export-Csv (Join-Path $ProjectRoot 'reports\handicap_postmatch_audit.csv') -NoTypeInformation -Encoding UTF8 -Append;$a|ConvertTo-Json
